import { describe, expect, test } from '@a0n/gnosis/test';
import {
  GNOSIS_PHYSICS_SANDBOX_LEAN_MODULES,
  PHYSICS_SANDBOX_NUMERIC_DISCLAIMER,
  SHANNON_FAIR_BINARY_NATS_JS,
  eulerStep,
  integrateConstVelocity,
  integrateLinearAutonomous,
  integrateLinearAutonomousRk2,
  rk2Step,
} from '../physics-sandbox';

describe('physics-sandbox numeric', () => {
  test('exposes Lean module anchors', () => {
    expect(GNOSIS_PHYSICS_SANDBOX_LEAN_MODULES).toContain('PhysicsSandbox');
    expect(GNOSIS_PHYSICS_SANDBOX_LEAN_MODULES).toContain(
      'ForkRaceFoldTheorems.ClassicalSandbox',
    );
    expect(GNOSIS_PHYSICS_SANDBOX_LEAN_MODULES.length).toBeGreaterThanOrEqual(4);
  });

  test('disclaimer is explicit', () => {
    expect(PHYSICS_SANDBOX_NUMERIC_DISCLAIMER.length).toBeGreaterThan(30);
    expect(PHYSICS_SANDBOX_NUMERIC_DISCLAIMER).toContain('Lean');
  });

  test('eulerStep matches one step of constant velocity', () => {
    const v = 3;
    const dt = 0.1;
    expect(eulerStep(0, 0, dt, () => v)).toBeCloseTo(v * dt);
  });

  test('integrateConstVelocity reaches v * span at endpoint', () => {
    const v = 2;
    const { xs, times } = integrateConstVelocity(v, 0, 1, 0.25);
    expect(times[times.length - 1]).toBeCloseTo(1);
    expect(xs[xs.length - 1]).toBeCloseTo(v * 1);
  });

  test('integrateConstVelocity interior samples match x = v * (t - t0)', () => {
    const v = -1.5;
    const t0 = 0.5;
    const { xs, times } = integrateConstVelocity(v, t0, 2.0, 0.1);
    for (let i = 0; i < times.length; i++) {
      expect(xs[i]).toBeCloseTo(v * (times[i]! - t0));
    }
  });

  test('SHANNON_FAIR_BINARY_NATS_JS tracks Math.LN2 (Lean fair-bit entropy anchor)', () => {
    expect(SHANNON_FAIR_BINARY_NATS_JS).toBe(Math.LN2);
    expect(SHANNON_FAIR_BINARY_NATS_JS).toBeCloseTo(0.6931471805599453);
  });

  test('integrateLinearAutonomous matches exp at moderate dt against x0 = 1', () => {
    const a = 0.3;
    const t0 = 0;
    const t1 = 1;
    const dt = 0.0001;
    const { xs, times } = integrateLinearAutonomous(a, 1, t0, t1, dt);
    const lastT = times[times.length - 1]!;
    const lastX = xs[xs.length - 1]!;
    expect(lastT).toBeCloseTo(t1);
    expect(lastX).toBeCloseTo(Math.exp(a * (lastT - t0)), 4);
  });

  test('integrateLinearAutonomous with a = 0 holds initial value', () => {
    const x0 = 2.25;
    const { xs } = integrateLinearAutonomous(0, x0, 0, 1, 0.1);
    for (const x of xs) {
      expect(x).toBeCloseTo(x0);
    }
  });

  test('RK2 is closer to exp than Euler for linear ODE at same dt', () => {
    const a = 0.4;
    const t1 = 1;
    const dt = 0.05;
    const exact = Math.exp(a * t1);
    const eulerLast = integrateLinearAutonomous(a, 1, 0, t1, dt).xs.at(-1)!;
    const rkLast = integrateLinearAutonomousRk2(a, 1, 0, t1, dt).xs.at(-1)!;
    expect(Math.abs(rkLast - exact)).toBeLessThan(Math.abs(eulerLast - exact));
  });

  test('rk2Step reduces to Euler when f is constant in x', () => {
    const dt = 0.2;
    expect(rk2Step(0, 1, dt, () => 3)).toBeCloseTo(eulerStep(0, 1, dt, () => 3));
  });
});
